CREATE VIEW INFORMATION_SCHEMA.STATISTICS\n(\n    `table_catalog` String,\n    `table_schema` String,\n    `table_name` String,\n    `non_unique` Int32,\n    `index_schema` String,\n    `index_name` Nullable(String),\n    `seq_in_index` UInt32,\n    `column_name` Nullable(String),\n    `collation` Nullable(String),\n    `cardinality` Nullable(Int64),\n    `sub_part` Nullable(Int64),\n    `packed` Nullable(String),\n    `nullable` String,\n    `index_type` String,\n    `comment` String,\n    `index_comment` String,\n    `is_visible` String,\n    `expression` Nullable(String),\n    `TABLE_CATALOG` String,\n    `TABLE_SCHEMA` String,\n    `TABLE_NAME` String,\n    `NON_UNIQUE` Int32,\n    `INDEX_SCHEMA` String,\n    `INDEX_NAME` Nullable(String),\n    `SEQ_IN_INDEX` UInt32,\n    `COLUMN_NAME` Nullable(String),\n    `COLLATION` Nullable(String),\n    `CARDINALITY` Nullable(Int64),\n    `SUB_PART` Nullable(Int64),\n    `PACKED` Nullable(String),\n    `NULLABLE` String,\n    `INDEX_TYPE` String,\n    `COMMENT` String,\n    `INDEX_COMMENT` String,\n    `IS_VISIBLE` String,\n    `EXPRESSION` Nullable(String)\n)\nSQL SECURITY INVOKER\nAS SELECT\n    \'\' AS table_catalog,\n    \'\' AS table_schema,\n    \'\' AS table_name,\n    0 AS non_unique,\n    \'\' AS index_schema,\n    NULL AS index_name,\n    0 AS seq_in_index,\n    NULL AS column_name,\n    NULL AS collation,\n    NULL AS cardinality,\n    NULL AS sub_part,\n    NULL AS packed,\n    \'\' AS nullable,\n    \'\' AS index_type,\n    \'\' AS comment,\n    \'\' AS index_comment,\n    \'\' AS is_visible,\n    NULL AS expression,\n    table_catalog AS TABLE_CATALOG,\n    table_schema AS TABLE_SCHEMA,\n    table_name AS TABLE_NAME,\n    non_unique AS NON_UNIQUE,\n    index_schema AS INDEX_SCHEMA,\n    index_name AS INDEX_NAME,\n    seq_in_index AS SEQ_IN_INDEX,\n    column_name AS COLUMN_NAME,\n    collation AS COLLATION,\n    cardinality AS CARDINALITY,\n    sub_part AS SUB_PART,\n    packed AS PACKED,\n    nullable AS NULLABLE,\n    index_type AS INDEX_TYPE,\n    comment AS COMMENT,\n    index_comment AS INDEX_COMMENT,\n    is_visible AS IS_VISIBLE,\n    expression AS EXPRESSION\nWHERE false
